import json
import logging
import os
from datetime import datetime, timezone

import azure.functions as func
from azure.identity import DefaultAzureCredential
from azure.storage.blob import BlobClient
from azure.cosmos import CosmosClient, PartitionKey
from azure.eventgrid import EventGridPublisherClient, EventGridEvent


app = func.FunctionApp()

logging.basicConfig(level=logging.INFO)

STORAGE_ACCOUNT_URL = os.environ.get("STORAGE_ACCOUNT_URL", "")
COSMOS_ENDPOINT = os.environ.get("COSMOS_ENDPOINT", "")
COSMOS_DATABASE = os.environ.get("COSMOS_DATABASE", "mvpdb")
COSMOS_CONTAINER = os.environ.get("COSMOS_CONTAINER", "results")
EVENTGRID_TOPIC_ENDPOINT = os.environ.get("EVENTGRID_TOPIC_ENDPOINT", "")
EVENTGRID_TOPIC_KEY = os.environ.get("EVENTGRID_TOPIC_KEY", "")
EVENTGRID_EVENT_TYPE = os.environ.get("EVENTGRID_EVENT_TYPE", "BlobProcessed")
EVENTGRID_SUBJECT_PREFIX = os.environ.get("EVENTGRID_SUBJECT_PREFIX", "mvp/blob")
COSMOS_PARTITION_KEY_PATH = os.environ.get("COSMOS_PARTITION_KEY_PATH", "/id")
BLOB_CONTAINER_NAME = os.environ.get("BLOB_CONTAINER_NAME", "")


def _credential():
    return DefaultAzureCredential(exclude_interactive_browser_credential=True)


def _get_blob_client(blob_url: str) -> BlobClient:
    return BlobClient.from_blob_url(blob_url, credential=_credential())


def _get_cosmos_container():
    client = CosmosClient(COSMOS_ENDPOINT, credential=_credential())
    db = client.get_database_client(COSMOS_DATABASE)
    try:
        container = db.get_container_client(COSMOS_CONTAINER)
        container.read()
        return container
    except Exception:
        try:
            db.create_container(
                id=COSMOS_CONTAINER,
                partition_key=PartitionKey(path=COSMOS_PARTITION_KEY_PATH),
            )
        except Exception:
            pass
        return db.get_container_client(COSMOS_CONTAINER)


def _send_event(subject: str, data: dict):
    if not EVENTGRID_TOPIC_ENDPOINT:
        return
    if EVENTGRID_TOPIC_KEY:
        client = EventGridPublisherClient(EVENTGRID_TOPIC_ENDPOINT, credential=EVENTGRID_TOPIC_KEY)
    else:
        client = EventGridPublisherClient(EVENTGRID_TOPIC_ENDPOINT, credential=_credential())
    event = EventGridEvent(
        subject=subject,
        data=data,
        event_type=EVENTGRID_EVENT_TYPE,
        data_version="1.0",
    )
    client.send([event])


def _process_content(content: bytes, blob_name: str) -> dict:
    text = content.decode("utf-8", errors="replace")
    lines = text.splitlines()
    words = text.split()
    return {
        "id": blob_name.replace("/", "_"),
        "blobName": blob_name,
        "processedAt": datetime.now(timezone.utc).isoformat(),
        "byteLength": len(content),
        "lineCount": len(lines),
        "wordCount": len(words),
        "preview": text[:1000],
    }


@app.function_name(name="ProcessBlob")
@app.blob_trigger(
    arg_name="blob",
    path="{container}/{name}",
    connection="AzureWebJobsStorage",
)
def process_blob(blob: func.InputStream):
    try:
        blob_name = blob.name
        logging.info("Processing blob: %s", blob_name)

        content = blob.read()
        result = _process_content(content, blob_name)

        container = _get_cosmos_container()
        container.upsert_item(result)

        _send_event(
            subject=f"{EVENTGRID_SUBJECT_PREFIX}/{blob_name}",
            data={
                "status": "processed",
                "blobName": blob_name,
                "resultId": result["id"],
                "processedAt": result["processedAt"],
                "byteLength": result["byteLength"],
            },
        )

        logging.info("Successfully processed blob: %s", blob_name)
    except Exception as e:
        logging.exception("Failed to process blob")
        try:
            _send_event(
                subject=f"{EVENTGRID_SUBJECT_PREFIX}/failed",
                data={
                    "status": "failed",
                    "error": str(e),
                    "blobName": getattr(blob, "name", None),
                    "processedAt": datetime.now(timezone.utc).isoformat(),
                },
            )
        except Exception:
            logging.exception("Failed to send failure event")
        raise


@app.function_name(name="Health")
@app.route(route="health", methods=["GET"], auth_level=func.AuthLevel.ANONYMOUS)
def health(req: func.HttpRequest) -> func.HttpResponse:
    return func.HttpResponse(
        json.dumps(
            {
                "status": "ok",
                "storageAccountUrl": STORAGE_ACCOUNT_URL,
                "cosmosEndpointConfigured": bool(COSMOS_ENDPOINT),
                "eventGridConfigured": bool(EVENTGRID_TOPIC_ENDPOINT),
                "blobContainerName": BLOB_CONTAINER_NAME,
            }
        ),
        mimetype="application/json",
        status_code=200,
    )